Here is a C++ program that reads a text file line by line and counts the number of occurrences of a specific word:

```cpp
#include <iostream>
#include <fstream>
#include <string>
using namespace std;

int main()
{
    const string word = "apple";
    ifstream file ("input.txt");
    int count = 0;

    while (file >> line)
    {
        count += count(line, word);
    }

    file.close();

    cout << "Occurrences of " << word << ": " << count << endl;
    return 0;
}

int count(string line, const string &word)
{
    int count = 0;
    string tokens[] = line.split(" ");
    for (int i = 0; i < tokens.length(); i++)
    {
        if (tokens[i].find(word)!= string::npos)
            count++;
    }
    return count;
}
```

